module adder_16bit (
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

    wire [7:0] sum_low;
    wire [7:0] sum_high;
    wire carry_out_low;
    wire carry_out_high;

    wire [8:0] adder_low_result;
    assign adder_low_result = {1'b0, a[7:0]} + {1'b0, b[7:0]} + Cin;
    assign sum_low = adder_low_result[7:0];
    assign carry_out_low = adder_low_result[8];

    wire [8:0] adder_high_result;
    assign adder_high_result = {1'b0, a[15:8]} + {1'b0, b[15:8]} + carry_out_low;
    assign sum_high = adder_high_result[7:0];
    assign carry_out_high = adder_high_result[8];

    assign y = {sum_high, sum_low};
    assign Co = carry_out_high;

endmodule
